mapper.select:
SELECT dmst.dvc_grp_id ,dmst.dvc_grp_nm ,dmst.dvc_grp_fg_cd ,cd.cd_nm as dvc_grp_fg_nm ,CASE WHEN dmst.dvc_grp_fg_cd = '01' THEN '0' ELSE TO_CHAR(dmst.grp_tgt_qty) END grpTgtQty ,dmst.use_yn ,dmst.dvc_grp_expl ,dmst.grp_tgt_cond_cts ,(select user_nm from ad_user_mst where user_id = dmst.stm_fir_reg_user_id) as regNm , to_char(dmst.stm_fir_reg_date,'yyyy.mm.dd hh24:mi') stm_fir_reg_date ,(select user_nm from ad_user_mst where user_id = dmst.stm_last_upd_user_id) as updNm ,to_char(dmst.stm_last_upd_date,'yyyy.mm.dd hh24:mi') stm_last_upd_date ,CASE WHEN (SELECT COUNT(*) FROM UM_UPD_PLAN_DVC_GRP_MAP WHERE dvc_grp_id = dmst.dvc_grp_id) > 0 THEN 'Y' ELSE 'N' END AS mapYn FROM dm_dvc_grp_mst dmst ,ad_comm_cd cd WHERE 1=1 AND dmst.DEL_YN = 'N' AND cd.comm_grp_cd = 'DVC_GRP_FG_CD' AND dmst.dvc_grp_fg_cd = cd.comm_cd
AND UPPER(dmst.dvc_grp_nm) LIKE '%' || UPPER(#{dvcGrpNm}) || '%'
AND dmst.dvc_grp_fg_cd = #{dvcGrpFgCd}
AND dmst.use_yn = #{useYn}
AND dmst.stm_fir_reg_user_id IN
#{value}
ORDER BY dmst.stm_last_upd_date desc

SELECT COUNT(*) OVER() TOTAL,
SELECT
/*+ PARALLEL(4) */ DDM.STB_ID ,DECODE(LENGTH(STB.USER_SERVICE_NUM),10,'상용','테스트용' ) STBDIVISION ,PS.MAC_ADDRESS ,(SELECT SM.MODEL_NAME FROM STB_MODEL SM WHERE SM.MODEL_CODE = PS.MODEL_CODE AND ROWNUM = 1) MODEL_NAME ,(SELECT MCM.CUG_NM FROM DM_CUG_MST DCM ,MN_CUG_MST MCM WHERE STB.SERVICE_CODE = DCM.CUG_ID AND DCM.CUG_ID = MCM.CUG_ID AND ROWNUM = 1) CUG_EXPL ,(SELECT COMM.CD_NM FROM AD_COMM_CD COMM WHERE COMM.COMM_GRP_CD = 'IPTV_STATUS_CODE' AND COMM.COMM_CD = STB.IPTV_STATUS_CODE AND ROWNUM = 1) CD_NM ,DDM.CLNT_IPADDR ,DDM.RCU_MANUFR_CD ,DDM.RCU_FIRM_VER ,DDM.CLNT_PUB_IPADDR ,DDM.STB_SW_VER STB_SW_PLAN_INST_VER ,DDM.STB_SW_PLAN_LAST_VER ,TO_CHAR(DDM.STM_UPTM, 'YYYY.MM.DD HH24:MI') STM_UPTM ,DECODE(DDM.STM_UPTM,NULL,'',TRUNC(SYSDATE) - TRUNC(DDM.STM_UPTM)||'일') AS OVERUPTIME ,'N' AS MYSTBYN ,(SELECT DQTM.TEAM_NM FROM DM_QLTY_TEAM_MST DQTM WHERE DDM.TEAM_CD = DQTM.TEAM_CD AND ROWNUM = 1) AREAQLTY ,STB.USER_SERVICE_NUM ,DECODE(DDM.HDMI_POW,'1','사용함','0','사용 안함',NULL) HDMI_POW ,DECODE(DDM.RCU_PAIRING,'1','Y','0','N',NULL) RCU_PAIRING ,DDM.TEAM_CD FROM STB STB ,DM_DVC_MST DDM ,PHYSICAL_STB PS
,DM_DVC_GRP_PSNL_MAP UDGPM ,DM_DVC_GRP_MST DDGM WHERE 1=1 AND DDGM.DVC_GRP_ID =#{dvcGrpId} AND DDGM.DVC_GRP_ID = UDGPM.DVC_GRP_ID AND UDGPM.STB_ID = DDM.STB_ID AND DDM.STB_ID = STB.STB_ID AND DDM.STB_ID = PS.STB_ID (+)
#{endRow}
